// MarkResultExecutionError preserves a populated worker result as a structured
// attempt failure. Callers use this when ExecuteBeadWithConfig returned both a
// result and an error; the presence of the result means DDx has enough
// execution context to report the attempt instead of aborting the process.
func MarkResultExecutionError(res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if res.Outcome == "" {
		res.Outcome = ExecuteBeadOutcomeTaskFailed
	}
	if res.Reason == "" {
		res.Reason = err.Error()
	}
	if res.Error == "" {
		res.Error = err.Error()
	}
	if res.Status == "" || res.Status == ExecuteBeadStatusNoChanges {
		res.Status = ClassifyExecuteBeadStatus("error", res.ExitCode, res.Reason)
	}
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
	if res.FailureMode == "" {
		res.FailureMode = FailureModeUnknown
	}
	// A pre-dispatch provider-boundary failure carries its typed classification
	// on the error (ddx-3b721804). Prefer it so the report's outcome_reason is
	// the precise provider taxonomy (provider_auth, provider_model_unavailable,
	// ...) rather than the coarse worker-level bucket.
	var pfErr *ProviderFailureError
	if errors.As(err, &pfErr) && pfErr.Failure.Reason != "" {
		res.FailureMode = pfErr.Failure.Reason
	}
}

// MarkResultLandError records a coordinator/landing failure on a completed
// worker result. When possible it first pins ResultRev under refs/ddx/iterations
// so the worker's commit remains reachable even though the target branch did
// not advance cleanly.
func MarkResultLandError(projectRoot string, res *ExecuteBeadResult, err error) {
	if res == nil || err == nil {
		return
	}
	if markReconciledAlreadyLanded(projectRoot, res, err) {
		return
	}
	reason := "land coordination failed: " + err.Error()
	if action, ok := classifyLandCoordinationAction(err.Error()); ok {
		switch action {
		case landCoordinationActionRetryLand:
			reason = "land coordination retry: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_retry"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandRetry
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandRetry
			return
		case landCoordinationActionOperatorAttention:
			reason = "land coordination operator attention: " + err.Error()
			preserveResultRefForLandError(projectRoot, res, &reason)
			res.Outcome = "land_coordination_operator_attention"
			res.Reason = reason
			res.Error = err.Error()
			res.Status = ExecuteBeadStatusLandOperatorAttention
			res.OrchestratorStatus = res.Status
			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
			res.FailureMode = FailureModeLandOperatorAttention
			return
		}
	}
	preserveResultRefForLandError(projectRoot, res, &reason)
	res.Outcome = "error"
	res.Reason = reason
	res.Error = err.Error()
	res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	res.OrchestratorStatus = res.Status
	res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
	res.FailureMode = classifyLandingFailureMode(res.Outcome, res.Reason, res.GateResults, res.FailureMode)
}

func preserveResultRefForLandError(projectRoot string, res *ExecuteBeadResult, reason *string) {
	if res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev {
		return
	}
	preserveRef := landIterationRef(res.BeadID, res.AttemptID, res.BaseRev)
	if upErr := (RealLandingGitOps{}).UpdateRefTo(projectRoot, preserveRef, res.ResultRev, ""); upErr == nil {
		res.PreserveRef = preserveRef
	} else if reason != nil {
		*reason = fmt.Sprintf("%s; preserving result failed: %v", *reason, upErr)
	}
}

type landCoordinationAction string

const (
	landCoordinationActionRetryLand         landCoordinationAction = "retry-land"
	landCoordinationActionOperatorAttention landCoordinationAction = "operator-attention"
)

func markReconciledAlreadyLanded(projectRoot string, res *ExecuteBeadResult, err error) bool {
	if projectRoot == "" || res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev || err == nil {
		return false
	}
	if !strings.Contains(strings.ToLower(err.Error()), "cannot lock ref") {
		return false
	}
	targets := landCoordinationTargetRefs(err.Error())
	targets = append(targets, "HEAD")
	for _, target := range targets {
		tip, ok := resultReachableFromRef(projectRoot, res.ResultRev, target)
		if !ok {
			continue
		}
		if res.ImplementationRev == "" {
			res.ImplementationRev = res.ResultRev
		}
		res.ResultRev = tip
		res.LandedRev = tip
		res.Outcome = "merged"
		res.Reason = "land coordination reconciled: result already landed"
		res.Error = err.Error()
		res.Status = ExecuteBeadStatusSuccess
		res.OrchestratorStatus = res.Status
		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
		res.FailureMode = ""
		return true
	}
	return false
}

func resultReachableFromRef(projectRoot, resultRev, ref string) (string, bool) {
	tipOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", ref).Output()
	if err != nil {
		return "", false
	}
	tip := strings.TrimSpace(string(tipOut))
	if tip == "" {
		return "", false
	}
	err = internalgit.Command(context.Background(), projectRoot, "merge-base", "--is-ancestor", resultRev, tip).Run()
	return tip, err == nil
}

func landCoordinationTargetRefs(msg string) []string {
	var refs []string
	for _, token := range strings.FieldsFunc(msg, func(r rune) bool {
		return r == '\'' || r == '"' || r == ':' || r == ' ' || r == '\n' || r == '\t'
	}) {
		token = strings.TrimSpace(token)
		if strings.HasPrefix(token, "refs/heads/") {
			refs = append(refs, token)
		}
	}
	return refs
}

func classifyLandCoordinationAction(msg string) (landCoordinationAction, bool) {
	lower := strings.ToLower(msg)
	if strings.Contains(lower, "staged changes after waiting") {
		paths := stagedPathsFromLandError(msg)
		if len(paths) > 0 && allGeneratedLandCoordinationPaths(paths) {
			return landCoordinationActionRetryLand, true
		}
		return landCoordinationActionOperatorAttention, true
	}
	if strings.Contains(lower, "cannot lock ref") {
		return landCoordinationActionRetryLand, true
	}
	return "", false
}

func stagedPathsFromLandError(msg string) []string {
	lines := strings.Split(msg, "\n")
	if len(lines) <= 1 {
		return nil
	}
	var paths []string
	for _, line := range lines[1:] {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if tab := strings.IndexByte(line, '\t'); tab >= 0 {
			line = line[tab+1:]
		}
		if p := strings.TrimSpace(line); p != "" {
			paths = append(paths, filepath.ToSlash(p))
		}
	}
	return paths
}

func allGeneratedLandCoordinationPaths(paths []string) bool {
	for _, p := range paths {
		if trackerpaths.IsManagedTrackerPath(p) ||
			strings.HasPrefix(p, ".ddx/executions/") ||
			strings.HasPrefix(p, ".ddx/runs/") ||
			strings.HasPrefix(p, ".ddx/metrics/") ||
			strings.HasPrefix(p, ".ddx/attachments/") {
			continue
		}
		return false
	}
	return true
}

// ReportFromExecuteBeadResult maps the detailed worker/orchestrator result
// into the loop-facing report shape used by ddx work and ddx try.
func ReportFromExecuteBeadResult(res *ExecuteBeadResult, powerClass string) ExecuteBeadReport {
	if res == nil {
		return ExecuteBeadReport{}
	}
	return ExecuteBeadReport{
		BeadID:                      res.BeadID,
		AttemptID:                   res.AttemptID,
		WorkerID:                    res.WorkerID,
		Harness:                     res.Harness,
		Provider:                    res.Provider,
		Model:                       res.Model,
		ActualPower:                 res.ActualPower,
		PredictedPower:              res.PredictedPower,
		PredictedSpeedTPS:           res.PredictedSpeedTPS,
		PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
		PredictedCostSource:         res.PredictedCostSource,
		Status:                      res.Status,
		Detail:                      res.Detail,
		Error:                       res.Error,
		Stderr:                      res.Stderr,
		RateLimitBudget:             res.RateLimitBudget,
		SessionID:                   res.SessionID,
		BaseRev:                     res.BaseRev,
		ResultRev:                   res.ResultRev,
		ImplementationRev:           res.ImplementationRev,
		LandedRev:                   res.LandedRev,
		TargetBranch:                res.TargetBranch,
		EvidenceRev:                 res.EvidenceRev,
		ProjectRoot:                 res.ProjectRoot,
		PreserveRef:                 res.PreserveRef,
		CandidateRef:                res.CandidateRef,
		CycleIndex:                  res.CycleIndex,
		NoChangesRationale:          res.NoChangesRationale,
		CycleTrace:                  append([]ExecutionCycleTrace(nil), res.CycleTrace...),
		PowerClass:                  powerClass,
		CostUSD:                     res.CostUSD,

func countPriorEscalationTriggers(reader BeadEventReader, beadID, resultRev string) int {
	if reader == nil || resultRev == "" {
		return 0
	}
	events, err := reader.Events(beadID)
	if err != nil {
		return 0
	}
	n := 0
	for _, ev := range events {
		if ev.Kind != "review-error" && ev.Kind != ReviewPairingDegradedEventKind {
			continue
		}
		m := reResultRevField.FindStringSubmatch(ev.Body)
		if m == nil || m[1] != resultRev {
			continue
		}
		n++
	}
	return n
}

// reviewerEscalatedEventBody renders the kind:reviewer-escalated event body.
func reviewerEscalatedEventBody(newMinPower, errorCount int, resultRev string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "new_min_power=%d\n", newMinPower)
	fmt.Fprintf(&b, "error_count=%d\n", errorCount)
	fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
	return b.String()
}

// ReviewBead implements BeadReviewer.
func (r *DefaultBeadReviewer) ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
	// Fetch the git diff for the commit being reviewed.
	diff, err := r.gitShow(resultRev)
	if err != nil {
		return nil, fmt.Errorf("reviewer: git show %s: %w", resultRev, err)
	}
	return r.reviewBeadWithDiff(ctx, beadID, resultRev, impl, diff, r.ProjectRoot)
}

// Review implements CandidateReviewer for the pre-land candidate-cycle path.
// It reviews the full base_rev..candidate_rev range and dispatches the reviewer
// inside the still-live attempt worktree.
func (r *DefaultBeadReviewer) Review(ctx context.Context, projectRoot string, candidate CandidateResult) (CandidateReviewResult, error) {
	reviewer := *r
	if reviewer.ProjectRoot == "" {
		reviewer.ProjectRoot = projectRoot
	}
	if reviewer.ProjectRoot == "" {
		return CandidateReviewResult{}, fmt.Errorf("candidate reviewer: project_root required")
	}
	beadID := candidate.Report.BeadID
	if beadID == "" {
		return CandidateReviewResult{}, fmt.Errorf("candidate reviewer: bead_id required")
	}
	diff, err := reviewer.gitDiff(candidate.Report.BaseRev, candidate.Report.ResultRev)
	if err != nil {
		return CandidateReviewResult{}, fmt.Errorf("candidate reviewer: git diff %s..%s: %w", candidate.Report.BaseRev, candidate.Report.ResultRev, err)
	}
	workDir := candidate.WorktreePath
	if workDir == "" {
		workDir = reviewer.ProjectRoot
	}
	impl := ImplementerRouting{
		Harness:     candidate.Report.Harness,
		Provider:    candidate.Report.Provider,
		Model:       candidate.Report.Model,
		ActualPower: candidate.Report.ActualPower,
		Correlation: map[string]string{
			"bead_id":       beadID,
			"attempt_id":    candidate.Report.AttemptID,
			"session_id":    candidate.Report.SessionID,
			"result_rev":    candidate.Report.ResultRev,
			"candidate_ref": candidate.Report.CandidateRef,
			"cycle_index":   fmt.Sprintf("%d", candidate.CycleIndex),
		},
	}
	// Read ac-check.json from the still-live worktree so the reviewer can
	// ratify mechanical results rather than re-grepping the diff.
	acCheckJSON := ""
	if candidate.Report.AttemptID != "" && candidate.WorktreePath != "" {
		acCheckPath := filepath.Join(candidate.WorktreePath, ExecuteBeadArtifactDir, candidate.Report.AttemptID, "ac-check.json")
		// evidence:allow-unbounded — ac-check.json is a small structured file (~1-2 kB)
		if data, readErr := os.ReadFile(acCheckPath); readErr == nil {
			acCheckJSON = string(data)
		}
	}
	group, groupErr := reviewer.reviewGroupWithDiff(ctx, beadID, candidate.Report.ResultRev, impl, diff, workDir, acCheckJSON)
	review, reduceErr := reducePreCloseReviewGroup(group)
	if review == nil {
		if reduceErr != nil {
			return CandidateReviewResult{}, reduceErr
		}
		return CandidateReviewResult{}, groupErr
	}
	out := CandidateReviewResult{
		Verdict:          string(review.Verdict),
		Rationale:        review.Rationale,
		PerAC:            append([]ReviewAC(nil), review.PerAC...),
		Findings:         append([]Finding(nil), review.Findings...),
		Classification:   ClassifyReviewFindings(review).Class,
		ReviewGroupID:    group.Bundle.GroupID,
		ReviewerIndices:  make([]int, 0, len(group.Slots)),
		ReviewerVerdicts: make([]string, 0, len(group.Slots)),
	}
	for _, slot := range group.Slots {
		out.ReviewerIndices = append(out.ReviewerIndices, slot.ReviewerIndex)
		if slot.Result == nil {
			out.ReviewerVerdicts = append(out.ReviewerVerdicts, "")
			continue
		}
		out.ReviewerVerdicts = append(out.ReviewerVerdicts, strings.TrimSpace(string(slot.Result.Verdict)))
	}
	if reduceErr != nil {
		return out, reduceErr
	}
	return out, groupErr
}

func (r *DefaultBeadReviewer) reviewBeadWithDiff(ctx context.Context, beadID, resultRev string, impl ImplementerRouting, diff, reviewWorkDir string) (*ReviewResult, error) {
	b, err := r.BeadStore.Get(ctx, beadID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: get bead %s: %w", beadID, err)
	}

	// Resolve governing document references.
	refs := ResolveGoverningRefs(r.ProjectRoot, b)

	// Determine iteration number from bead events.
	iter := 1

	// Count prior escalation triggers so reviewerDispatchProfile can bump
	// MinPower on retries.
	priorErrors := countPriorEscalationTriggers(r.EventReader, beadID, resultRev)

	// Build the review prompt under evidence caps.
	caps := r.Caps
	if caps.MaxPromptBytes == 0 {
		caps = evidence.DefaultCaps()
	}
	built := BuildReviewPromptBounded(b, iter, resultRev, diff, r.ProjectRoot, refs, BuildReviewPromptOptions{Caps: caps})
	prompt := built.Prompt
	attemptID := GenerateAttemptID()
	artifacts, err := createArtifactBundle(r.ProjectRoot, r.ProjectRoot, attemptID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: create artifact bundle: %w", err)
	}
	if err := os.WriteFile(artifacts.PromptAbs, []byte(prompt), 0o644); err != nil {
		return nil, fmt.Errorf("reviewer: write prompt artifact: %w", err)
	}

	// Pre-dispatch short-circuit (FEAT-022 §7): if the assembled prompt
	// exceeds MaxPromptBytes after all per-section trimming, skip the
	// provider dispatch and return a typed review-error: context_overflow.
	// The bead is NOT closed — the loop's review-error event-append path
	// records the failure and leaves the bead open for retry.
	if built.Overflow {
		baseRev := resolveReviewBaseRev(r.ProjectRoot, resultRev)
		reviewProfile := r.reviewerDispatchProfile(ctx, impl, priorErrors)
		reviewRouteLabel := reviewProfile.Name
		if r.Model != "" {
			reviewRouteLabel = r.Model
		}
		overflowTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			Harness:     r.Harness,
			Model:       reviewRouteLabel,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Error:           evidence.OutcomeReviewContextOverflow,
			Rationale:       evidence.OutcomeReviewContextOverflow,
			ReviewerHarness: r.Harness,
			ReviewerModel:   reviewRouteLabel,
			BaseRev:         baseRev,
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			CostUSD:         0,
			InputBytes:      overflowTelemetry.InputBytes,
			OutputBytes:     overflowTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          r.Harness,
			Model:            reviewRouteLabel,
			BaseRev:          baseRev,
			ResultRev:        resultRev,
			Verdict:          string(VerdictBlock),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: overflowTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(VerdictBlock),
			Error:            evidence.OutcomeReviewContextOverflow,
			EvidenceAssembly: overflowTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: PROMPT_BUDGET_EXCEEDED/context_overflow (assembled prompt %d bytes exceeds cap %d; see %s)",
			len(prompt), caps.MaxPromptBytes, artifacts.DirRel)
	}

	// Resolve reviewer routing. An explicit reviewer harness/model wins as an
	// operator override; otherwise DDx sends only a fizeau profile hint plus
	// the reviewer MinPower floor.
	reviewHarness := r.Harness
	reviewProfile := r.reviewerDispatchProfile(ctx, impl, priorErrors)
	// Emit reviewer-escalated event when MinPower is bumped above baseline.
	if priorErrors > 0 && r.BeadEvents != nil {
		_ = r.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
			Kind:      ReviewerEscalatedEventKind,
			Summary:   fmt.Sprintf("reviewer escalated to min_power=%d after %d prior error(s)", reviewProfile.MinPower, priorErrors),
			Body:      reviewerEscalatedEventBody(reviewProfile.MinPower, priorErrors, resultRev),
			Source:    "ddx work",
			CreatedAt: time.Now().UTC(),
		})
	}

	start := time.Now()
	runRuntime := BuildReviewExecuteRequest(impl, reviewHarness, reviewProfile.Name)
	// Apply escalated MinPower: use the higher of the base R4 floor and the
	// escalated profile floor so retries reach a stronger reviewer powerClass.
	if reviewProfile.MinPower > runRuntime.MinPowerOverride {
		runRuntime.MinPowerOverride = reviewProfile.MinPower
	}
	reviewRouteLabel := r.applyExplicitReviewerPins(&runRuntime)
	runRuntime.Prompt = prompt
	runRuntime.WorkDir = reviewWorkDir
	result, runErr := r.dispatchReviewRun(ctx, runRuntime)

	durationMS := int(time.Since(start).Milliseconds())
	if runErr != nil {
		// Transport-class failure (FEAT-022 §12): network or provider-side
		// error. Surface as a typed review-error so the loop classifies and
		// counts it correctly, rather than masquerading as a BLOCK verdict.
		transportTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			ElapsedMS:   durationMS,
			Harness:     reviewHarness,
			Model:       reviewRouteLabel,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       runErr.Error(),
			Error:           evidence.OutcomeReviewTransport,
			ReviewerHarness: reviewHarness,
			ReviewerModel:   reviewRouteLabel,
			BaseRev:         resolveReviewBaseRev(r.ProjectRoot, resultRev),
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			DurationMS:      durationMS,
			CostUSD:         resultCost(result),
			InputBytes:      transportTelemetry.InputBytes,
			OutputBytes:     transportTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          reviewHarness,
			Model:            reviewRouteLabel,
			BaseRev:          reviewRes.BaseRev,
			ResultRev:        resultRev,
			Verdict:          string(reviewRes.Verdict),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: transportTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(reviewRes.Verdict),
			Rationale:        reviewRes.Rationale,
			Error:            reviewRes.Error,
			EvidenceAssembly: transportTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: %s: %w", evidence.OutcomeReviewTransport, runErr)
	}

	actualHarness := reviewHarness
	actualModel := reviewRouteLabel
	actualProvider := ""
	actualPower := 0
	if result != nil {
		if result.Harness != "" {
			actualHarness = result.Harness
		}
		if result.Model != "" {
			actualModel = result.Model
		}
		actualProvider = result.Provider
		actualPower = result.ActualPower
		durationMS = result.DurationMS
	}

	output := ""
	sessionID := ""
	if result != nil {
		output = result.Output
		sessionID = result.AgentSessionID
	}
	// Strict JSON parse: replaces the legacy markdown extractor that silently
	// pulled "BLOCK" from the prompt's options-header line whenever the model
	// echoed it back (the upstream-report regression). On parse error we emit
	// a typed review-error class — the work leaves the bead open for
	// retry rather than mis-recording a BLOCK verdict.
	parsed, parseErr := ParseReviewVerdict([]byte(output))
	var strictVerdict Verdict
	var rationale string
	var findings []Finding
	if parseErr == nil {
		strictVerdict = parsed.Verdict
		rationale = strings.TrimSpace(parsed.Summary)
		findings = parsed.Findings
		if rationale == "" && len(findings) > 0 {
			parts := make([]string, 0, len(findings))
			for _, f := range findings {
				line := strings.TrimSpace(f.Summary)
				if line == "" {
					continue
				}
				if f.Location != "" {
					line = f.Location + ": " + line
				}
				parts = append(parts, line)
			}
			rationale = strings.Join(parts, "\n")
		}
	}
	baseRev := resolveReviewBaseRev(r.ProjectRoot, resultRev)
	telemetry := &EvidenceAssemblyTelemetry{
		Sections:    built.Sections,
		InputBytes:  len(prompt),
		OutputBytes: len(output),
		ElapsedMS:   durationMS,
		Harness:     actualHarness,
		Model:       actualModel,
	}
	reviewRes := &ReviewResult{
		Verdict:          strictVerdict,
		Rationale:        rationale,
		PerAC:            parsed.PerAC,
		Findings:         findings,
		ProseFindings:    parsed.ProseFindings,
		RawOutput:        output,
		ReviewerHarness:  actualHarness,
		ReviewerModel:    actualModel,
		ReviewerProvider: actualProvider,
		SessionID:        sessionID,
		BaseRev:          baseRev,
		ResultRev:        resultRev,
		ExecutionDir:     artifacts.DirRel,
		DurationMS:       durationMS,
		CostUSD:          resultCost(result),
		InputBytes:       telemetry.InputBytes,
		OutputBytes:      telemetry.OutputBytes,
	}

	// R4 pairing-degradation telemetry: when MinPower=actualPower+1 fails
	// to push the reviewer onto a different provider than the implementer,
	// surface a kind:review-pairing-degraded event so operators can see the
	// regression. The result_rev is included in the body so the event can be
	// counted as an escalation trigger for subsequent dispatches.
	// Best-effort only — emission failures never affect the review outcome.
	if r.BeadEvents != nil && actualProvider != "" && impl.Provider != "" && actualProvider == impl.Provider {
		_ = r.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
			Kind:      ReviewPairingDegradedEventKind,
			Summary:   fmt.Sprintf("reviewer pinned to same provider as implementer (%s)", impl.Provider),
			Body:      reviewPairingDegradedBody(impl, actualHarness, actualProvider, actualModel, actualPower, resultRev),
			Source:    "ddx work",
			CreatedAt: time.Now().UTC(),
		})
	}
	_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
		Harness:          actualHarness,
		Model:            actualModel,
		SessionID:        sessionID,
		BaseRev:          baseRev,
		ResultRev:        resultRev,
		Verdict:          string(strictVerdict),
		BeadID:           beadID,
		ExecutionDir:     artifacts.DirRel,
		EvidenceAssembly: telemetry,
	}, reviewArtifactResult{
		Verdict:          string(strictVerdict),
		Rationale:        rationale,
		PerAC:            parsed.PerAC,
		Findings:         findings,
		ProseFindings:    parsed.ProseFindings,
		Error:            reviewRes.Error,
		EvidenceAssembly: telemetry,
	})
	if parseErr != nil {
		// FEAT-022 §12: distinguish provider_empty (zero bytes) from
		// unparseable (text without a recognizable JSON contract). Operators
		// triage these differently — provider_empty often signals a context-
		// window or backend availability issue, while unparseable signals a
		// reviewer-prompt or output-format drift.
		class := evidence.OutcomeReviewUnparseable
		if strings.TrimSpace(output) == "" {
			class = evidence.OutcomeReviewProviderEmpty
		}
		reviewRes.Error = class
		return reviewRes, fmt.Errorf("reviewer: %s: %w (raw output %d bytes; see %s)", class, parseErr, len(output), artifacts.DirRel)
	}

package evidence

import "strings"

// EvidenceAssemblySection is the per-section telemetry record produced by
// the evidence-assembly call sites and consumed by Stages C1, C2, and F
// (FEAT-022 §15). The shape is a contract — downstream stages decode this
// without re-deriving field names.
type EvidenceAssemblySection struct {
	Name             string   `json:"name"`
	BytesIncluded    int      `json:"bytes_included"`
	BytesOmitted     int      `json:"bytes_omitted"`
	TruncationReason string   `json:"truncation_reason"`
	SelectedItems    []string `json:"selected_items"`
	OmittedItems     []string `json:"omitted_items"`
}

// SectionInput is one candidate section handed to FitSections, in
// caller-determined priority order (highest priority first).
type SectionInput struct {
	Name    string
	Content string
	// MinFloor, when true, marks this section as part of the minimum
	// evidence floor (FEAT-022 §5 items 1-2). Floor sections are always
	// included; if even the floor exceeds budget FitSections still
	// emits them but reports the overall overflow via the returned
	// TotalBytes vs budget comparison left to the caller.
	MinFloor bool
	// PerSectionCap, if non-zero, additionally clamps this section to
	// at most this many bytes (using ClampOutput) before budgeting.
	PerSectionCap int
}

// FitResult is the outcome of FitSections.
type FitResult struct {
	Included   []SectionInput
	Omitted    []SectionInput
	TotalBytes int
	Sections   []EvidenceAssemblySection
}

// FitSections selects sections to include under a total byte budget,
// in priority order. Floor sections are always included. Non-floor
// sections are added in order while their content fits the remaining
// budget; sections that don't fit are recorded as omitted.
//
// Default behavior is line-based and type-agnostic (FEAT-022 §1):
// when a section's PerSectionCap is non-zero, content is clamped to
// that cap before budgeting. Markdown-aware extraction is handled by
// callers that need it; this primitive does not parse content.
func FitSections(sections []SectionInput, budget int) FitResult {
	if budget < 0 {
		budget = 0
	}
	res := FitResult{
		Sections: make([]EvidenceAssemblySection, 0, len(sections)),
	}
	used := 0

	// First pass: include all floor sections (apply per-section cap).
	for _, s := range sections {
		if !s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		section := EvidenceAssemblySection{
			Name:          s.Name,
			BytesIncluded: len(content),
			BytesOmitted:  len(s.Content) - len(content),
			SelectedItems: []string{s.Name},
		}
		if reason != "" {
			section.TruncationReason = reason
		}
		used += len(content)
		res.Included = append(res.Included, SectionInput{
			Name: s.Name, Content: content, MinFloor: true,
		})
		res.Sections = append(res.Sections, section)
	}

	// Second pass: non-floor in priority order, fit under remaining budget.
	for _, s := range sections {
		if s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		remaining := budget - used
		if len(content) <= remaining {
			used += len(content)
			res.Included = append(res.Included, SectionInput{
				Name: s.Name, Content: content,
			})
			section := EvidenceAssemblySection{
				Name:          s.Name,
				BytesIncluded: len(content),
				BytesOmitted:  len(s.Content) - len(content),
				SelectedItems: []string{s.Name},
			}
			if reason != "" {
				section.TruncationReason = reason
			}
			res.Sections = append(res.Sections, section)
			continue
		}
		// Doesn't fit even at PerSectionCap — try line-trim to fit.
		if remaining > 0 {
			trimmed := trimToLineBudget(content, remaining-len(TruncationMarker))
			if trimmed != "" {
				body := trimmed + TruncationMarker
				used += len(body)
				res.Included = append(res.Included, SectionInput{
					Name: s.Name, Content: body,
				})
				res.Sections = append(res.Sections, EvidenceAssemblySection{
					Name:             s.Name,
					BytesIncluded:    len(body),
					BytesOmitted:     len(s.Content) - len(body),
					TruncationReason: "budget",
					SelectedItems:    []string{s.Name},
				})
				continue
			}
		}
		// No room: omit entirely.
		res.Omitted = append(res.Omitted, s)
		res.Sections = append(res.Sections, EvidenceAssemblySection{
			Name:             s.Name,
			BytesIncluded:    0,
			BytesOmitted:     len(s.Content),
			TruncationReason: "budget",
			OmittedItems:     []string{s.Name},
		})
	}
	res.TotalBytes = used
	return res
}

func capContent(s SectionInput) (string, string) {
	if s.PerSectionCap <= 0 || len(s.Content) <= s.PerSectionCap {
		return s.Content, ""
	}
	clamped, truncated, _ := ClampOutput(s.Content, s.PerSectionCap)
	if truncated {
		return clamped, "per_section_cap"
	}
	return clamped, ""
}

// trimToLineBudget returns the longest prefix of s, ending on a line
// boundary, whose length is at most budget. Returns "" if budget <= 0
// or the first line alone exceeds budget.
func trimToLineBudget(s string, budget int) string {
	if budget <= 0 {
		return ""
	}
	if len(s) <= budget {
		return s
	}
	cut := strings.LastIndexByte(s[:budget], '\n')
	if cut <= 0 {
		return ""
	}
	return s[:cut+1]
}
